    // ---- Private Helpers ----

    private fun timestamp(): String {
        return SimpleDateFormat("yyyy-MM-dd HH:mm:ss.SSS Z", Locale.US).format(Date())
    }

    private fun sanitizeUsername(username: String): String {
        if (username.length <= 3) return "***"
        return "${username.take(2)}${"*".repeat(username.length - 3)}${username.takeLast(1)}"
    }

    private fun sanitizeHeader(key: String, value: String): String {
        val sensitiveHeaders = setOf(
            "authorization", "cookie", "set-cookie",
            "x-api-key", "x-auth-token", "proxy-authorization"
        )
        return if (key.lowercase() in sensitiveHeaders) {
            if (value.length > 10) {
                "${value.take(6)}...${value.takeLast(4)} [REDACTED]"
            } else {
                "[REDACTED]"
            }
        } else {
            value
        }
    }

    private fun sanitizeDbParam(value: Any?): String {
        return when (value) {
            null -> "NULL"
            is String -> if (value.length > 200) "${value.take(200)}... [TRUNCATED, total=${value.length}]" else "'$value'"
            is ByteArray -> "[BLOB, size=${value.size}]"
            else -> value.toString()
        }
    }

    private fun truncateBody(body: String, maxLength: Int = 5000): String {
        return if (body.length > maxLength) {
            "${body.take(maxLength)}\n... [TRUNCATED, total=${body.length} chars]"
        } else {
            body
        }
    }

    private fun getStackTraceString(throwable: Throwable): String {
        val sw = StringWriter()
        val pw = PrintWriter(sw)
        throwable.printStackTrace(pw)
        pw.flush()
        return sw.toString()
    }
}

