// ============================================================
// File Logging Tree - Writes logs to file for production diagnostics
// ============================================================

class FileLoggingTree(context: Context) : Timber.Tree() {

    private val logDir: File = File(context.filesDir, "logs")
    private val dateFormat = SimpleDateFormat("yyyy-MM-dd HH:mm:ss.SSS", Locale.US)
    private val fileDateFormat = SimpleDateFormat("yyyy-MM-dd", Locale.US)
    private val executor = Executors.newSingleThreadExecutor()
    private val recentLogs = ConcurrentLinkedQueue<String>()
    private val maxRecentLogs = 500
    private val maxLogFileSizeBytes = 10 * 1024 * 1024L // 10MB
    private val maxLogFileAgeDays = 7

    init {
        logDir.mkdirs()
        cleanOldLogs()
    }

    override fun isLoggable(tag: String?, priority: Int): Boolean {
        // Log everything in verbose mode for production diagnostics
        return true
    }

    override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
        val priorityChar = when (priority) {
            Log.VERBOSE -> 'V'
            Log.DEBUG -> 'D'
            Log.INFO -> 'I'
            Log.WARN -> 'W'
            Log.ERROR -> 'E'
            Log.ASSERT -> 'A'
            else -> '?'
        }

        val timestamp = dateFormat.format(Date())
        val threadName = Thread.currentThread().name
        val logLine = buildString {
            append("$timestamp [$priorityChar/$tag] [${threadName}] $message")
            if (t != null) {
                append("\n")
                val sw = StringWriter()
                t.printStackTrace(PrintWriter(sw))
                append(sw.toString())
            }
        }

        // Add to recent logs buffer
        recentLogs.add(logLine)
        while (recentLogs.size > maxRecentLogs) {
            recentLogs.poll()
        }

        // Write to file asynchronously
        executor.execute {
            try {
                val logFile = getOrCreateLogFile()
                FileWriter(logFile, true).use { writer ->
                    writer.appendLine(logLine)
                }

                // Rotate if file is too large
                if (logFile.length() > maxLogFileSizeBytes) {
                    rotateLogFile(logFile)
                }
            } catch (e: Exception) {
                // Fallback to Android log if file writing fails
                Log.e("FileLoggingTree", "Failed to write log to file", e)
            }
        }
    }

    fun getCurrentLogFile(): File? {
        val today = fileDateFormat.format(Date())
        val file = File(logDir, "app_log_$today.log")
        return if (file.exists()) file else null
    }

    fun getRecentLogs(count: Int): List<String> {
        return recentLogs.toList().takeLast(count)
    }

    fun flush() {
        executor.execute {
            // Force flush by writing a marker
            try {
                val logFile = getOrCreateLogFile()
                FileWriter(logFile, true).use { writer ->
                    writer.appendLine("--- LOG FLUSH at ${dateFormat.format(Date())} ---")
                }
            } catch (e: Exception) {
                Log.e("FileLoggingTree", "Failed to flush logs", e)
            }
        }
    }

    private fun getOrCreateLogFile(): File {
        val today = fileDateFormat.format(Date())
        val file = File(logDir, "app_log_$today.log")
        if (!file.exists()) {
            file.createNewFile()
            file.appendText("=== Log started at ${dateFormat.format(Date())} ===\n")
            file.appendText("=== Device: ${Build.MANUFACTURER} ${Build.MODEL} ===\n")
            file.appendText("=== Android: ${Build.VERSION.RELEASE} (API ${Build.VERSION.SDK_INT}) ===\n\n")
        }
        return file
    }

    private fun rotateLogFile(file: File) {
        val rotatedFile = File(logDir, "${file.nameWithoutExtension}_${System.currentTimeMillis()}.log.old")
        file.renameTo(rotatedFile)
    }

    private fun cleanOldLogs() {
        executor.execute {
            try {
                val cutoffTime = System.currentTimeMillis() - (maxLogFileAgeDays * 24 * 60 * 60 * 1000L)
                logDir.listFiles()?.forEach { file ->
                    if (file.lastModified() < cutoffTime) {
                        file.delete()
                    }
                }
            } catch (e: Exception) {
                Log.e("FileLoggingTree", "Failed to clean old logs", e)
            }
        }
    }
}

// ============================================================
// OkHttp Logging Interceptor - Full request/response logging
// ============================================================

class ComprehensiveHttpLoggingInterceptor : Interceptor {

    override fun intercept(chain: Interceptor.Chain): Response {
        val request = chain.request()
        val requestId = UUID.randomUUID().toString().take(8)
        val startTime = System.currentTimeMillis()

        // Log the request
        logRequest(request, requestId)

        return try {
            val response = chain.proceed(request)
            val duration = System.currentTimeMillis() - startTime

            // Log the response (need to read and recreate body)
            logResponse(request, response, requestId, duration)

            response
        } catch (e: Exception) {
            val duration = System.currentTimeMillis() - startTime
            AppLogger.logApiError(
                method = request.method,
                url = request.url.toString(),
                exception = e,
                requestId = requestId,
                durationMs = duration,
                metadata = mapOf(
                    "connectionTimeout" to chain.connectTimeoutMillis(),
                    "readTimeout" to chain.readTimeoutMillis()
                )
            )
            throw e
        }
    }

    private fun logRequest(request: Request, requestId: String) {
        val headers = mutableMapOf<String, String>()
        request.headers.forEach { (name, value) ->
            headers[name] = value
        }

        val body = request.body?.let { body ->
            try {
                val buffer = Buffer()
                body.writeTo(buffer)
                buffer.readUtf8()
            } catch (e: Exception) {
                "[Failed to read body: ${e.message}]"
            }
        }

        AppLogger.logApiRequest(
            method = request.method,
            url = request.url.toString(),
            headers = headers,
            body = body,
            requestId = requestId,
            metadata = mapOf(
                "contentType" to request.body?.contentType()?.toString(),
                "contentLength" to request.body?.contentLength(),
                "cacheControl" to request.cacheControl.toString()
            )
        )
    }

    private fun logResponse(request: Request, response: Response, requestId: String, duration: Long): Response {
        val headers = mutableMapOf<String, String>()
        response.headers.forEach { (name, value) ->
            headers[name] = value
        }

        // Read the response body
        val responseBody = response.body
        val bodyString = responseBody?.let {
            try {
                val source = it.source()
                source.request(Long.MAX_VALUE)
                val buffer = source.buffer.clone()
                buffer.readUtf8()
            } catch (e: Exception) {
                "[Failed to read response body: ${e.message}]"
            }
        }

        AppLogger.logApiResponse(
            method = request.method,
            url = request.url.toString(),
            statusCode = response.code,
            headers = headers,
            body = bodyString,
            requestId = requestId,
            durationMs = duration,
            metadata = mapOf(
                "protocol" to response.protocol.toString(),
                "message" to response.message,
                "isRedirect" to response.isRedirect,
                "cacheResponse" to (response.cacheResponse != null),
                "networkResponse" to (response.networkResponse != null),
                "contentType" to responseBody?.contentType()?.toString(),
                "contentLength" to responseBody?.contentLength()
            )
        )

        return response
    }
}

// ============================================================
// Database Logger Helper - Wraps database operations with logging
// ============================================================

class DatabaseLogger(private val dbName: String = "default") {

    fun <T> logQuery(
        query: String,
        parameters: Map<String, Any?> = emptyMap(),
        tableName: String? = null,
        operation: DatabaseOperation = DatabaseOperation.SELECT,
        block: () -> T
    ): T {
        val startTime = System.currentTimeMillis()
        return try {
            val result = block()
            val duration = System.currentTimeMillis() - startTime

            val rowsAffected = when (result) {
                is List<*> -> result.size
                is Int -> result
                is Long -> result.toInt()
                else -> null
            }

            AppLogger.logDatabaseQuery(
                query = query,
                parameters = parameters,
                tableName = tableName,
                operationType = operation,
                executionTimeMs = duration,
                rowsAffected = rowsAffected,
                metadata = mapOf("database" to dbName)
            )
            result
        } catch (e: Exception) {
            val duration = System.currentTimeMillis() - startTime
            AppLogger.logDatabaseError(
                query = query,
                parameters = parameters,
                exception = e,
                tableName = tableName,
                operationType = operation,
                metadata = mapOf(
                    "database" to dbName,
                    "executionTimeMs" to duration
                )
            )
            throw e
        }
    }

    fun <T> logTransaction(
        transactionId: String = UUID.randomUUID().toString().take(8),
        block: (TransactionLogger) -> T
    ): T {
        val transactionLogger = TransactionLogger(transactionId)
        val startTime = System.currentTimeMillis()

        AppLogger.logDatabaseTransaction(
            transactionId = transactionId,
            status = TransactionStatus.STARTED
        )

        return try {
            val result = block(transactionLogger)
            val duration = System.currentTimeMillis() - startTime

            AppLogger.logDatabaseTransaction(
                transactionId = transactionId,
                status = TransactionStatus.COMMITTED,
                queries = transactionLogger.getQueries(),
                executionTimeMs = duration
            )
            result
        } catch (e: Exception) {
            val duration = System.currentTimeMillis() - startTime

            AppLogger.logDatabaseTransaction(
                transactionId = transactionId,
                status = TransactionStatus.FAILED,
                queries = transactionLogger.getQueries(),
                executionTimeMs = duration,
                exception = e
            )
            throw e
        }
    }

    class TransactionLogger(val transactionId: String) {
        private val queries = mutableListOf<String>()

        fun addQuery(query: String) {
            queries.add(query)
        }

        fun getQueries(): List<String> = queries.toList()
    }
}

// ============================================================
// Auth Logger Helper - Convenience wrapper for auth operations
// ============================================================

class AuthLogger {

    fun <T> logLoginAttempt(
        username: String,
        method: String = "password",
        metadata: Map<String, Any?> = emptyMap(),
        block: () -> T
    ): T {
        AppLogger.logAuthAttempt(username, method, metadata)

        return try {
            val result = block()
            AppLogger.logAuthSuccess(
                username = username,
                method = method,
                metadata = metadata
            )
            result
        } catch (e: Exception) {
            AppLogger.logAuthFailure(
                username = username,
                method = method,
                reason = e.message ?: "Unknown error",
                exception = e,
                metadata = metadata
            )
            throw e
        }
    }

    fun logFailedLogin(
        username: String,
        reason: String,
        errorCode: Int? = null,
        method: String = "password",
        exception: Throwable? = null
    ) {
        AppLogger.logAuthFailure(
            username = username,
            method = method,
            reason = reason,
            errorCode = errorCode,
            exception = exception
        )
    }
}

// ============================================================
// Performance Timer Utility
// ============================================================

class PerformanceTimer(private val operationName: String) {
    private val startTime = System.currentTimeMillis()
    private val checkpoints = mutableListOf<Pair<String, Long>>()

    fun checkpoint(name: String) {
        checkpoints.add(name to System.currentTimeMillis())
    }

    fun stop(metadata: Map<String, Any?> = emptyMap()) {
        val totalDuration = System.currentTimeMillis() - startTime
        val allMetadata = metadata.toMutableMap()

        if (checkpoints.isNotEmpty()) {
            var previousTime = startTime
            val checkpointData = checkpoints.map { (name, time) ->
                val delta = time - previousTime
                previousTime = time
                "$name: ${delta}ms"
            }
            allMetadata["checkpoints"] = checkpointData.joinToString(", ")
        }

        AppLogger.logPerformance(operationName, totalDuration, allMetadata)
    }
}

// ============================================================
// OkHttpClient Builder Extension
// ============================================================

fun OkHttpClient.Builder.addComprehensiveLogging(): OkHttpClient.Builder {
    return this.addInterceptor(ComprehensiveHttpLoggingInterceptor())
}

// ============================================================
// Usage Examples (for reference)
// ============================================================

object LoggingUsageExamples {

    fun demonstrateAuthLogging() {
        val authLogger = AuthLogger()

        // Successful login
        try {
            authLogger.logLoginAttempt(
                username = "john.doe@example.com",
                method = "email_password",
                metadata = mapOf("ipAddress" to "192.168.1.1", "deviceId" to "abc123")
            ) {
                // Perform actual login
                "auth_token_here"
            }
        } catch (e: Exception) {
            // Already logged by AuthLogger
        }

        // Manual failure logging
        authLogger.logFailedLogin(
            username = "john.doe@example.com",
            reason = "Invalid credentials",
            errorCode = 401,
            method = "email_password"
        )

        // Token refresh
        AppLogger.logAuthTokenRefresh(
            success = true,
            metadata = mapOf("tokenExpiry" to "2024-12-31T23:59:59Z")
        )

        // Logout
        AppLogger.logLogout(
            username = "john.doe@example.com",
            reason = "session_expired"
        )
    }

    fun demonstrateDatabaseLogging() {
        val dbLogger = DatabaseLogger("main_db")

        // Simple query
        dbLogger.logQuery(
            query = "SELECT * FROM users WHERE id = ? AND active = ?",
            parameters = mapOf("id" to 42, "active" to true),
            tableName = "users",
            operation = DatabaseOperation.SELECT
        ) {
            // Execute actual query
            listOf("user1", "user2")
        }

        // Transaction
        dbLogger.logTransaction { txLogger ->
            txLogger.addQuery("INSERT INTO orders (user_id, total) VALUES (42, 99.99)")
            txLogger.addQuery("UPDATE users SET order_count = order_count + 1 WHERE id = 42")
            // Execute actual transaction
        }
    }

    fun demonstrateApiLogging() {
        // Using OkHttp with the interceptor
        val client = OkHttpClient.Builder()
            .addComprehensiveLogging()
            .build()

        // Manual API logging
        AppLogger.logApiRequest(
            method = "POST",
            url = "https://api.example.com/v1/users",
            headers = mapOf(
                "Content-Type" to "application/json",
                "Authorization" to "Bearer eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9..."
            ),
            body = """{"name": "John Doe", "email": "john@example.com"}""",
            requestId = "req_abc123"
        )

        AppLogger.logApiResponse(
            method = "POST",
            url = "https://api.example.com/v1/users",
            statusCode = 201,
            headers = mapOf("Content-Type" to "application/json"),
            body = """{"id": 42, "name": "John Doe"}""",
            requestId = "req_abc123",
            durationMs = 342
        )
    }

    fun demonstrateExceptionLogging() {
        try {
            throw IllegalStateException("Something went wrong", NullPointerException("Null value"))
        } catch (e: Exception) {
            AppLogger.logException(
                tag = "BUSINESS_LOGIC",
                throwable = e,
                metadata = mapOf(
                    "userId" to 42,
                    "screen" to "ProfileScreen",
                    "action" to "updateProfile"
                )
            )
        }
    }

    fun demonstratePerformanceLogging() {
        val timer = PerformanceTimer("loadUserProfile")
        // Step 1: Fetch from cache
        timer.checkpoint("cache_check")
        // Step 2: API call
        timer.checkpoint("api_call")
        // Step 3: Parse response
        timer.checkpoint("parse_response")
        // Step 4: Save to DB
        timer.checkpoint("save_to_db")
        timer.stop(mapOf("userId" to 42, "cacheHit" to false))
    }

    fun demonstrateNavigationLogging() {
        AppLogger.logScreenView(
            "ProfileScreen",
            mapOf("userId" to 42, "source" to "deep_link")
        )

        AppLogger.logUserAction(
            "button_click",
            mapOf("buttonId" to "save_profile", "screen" to "ProfileScreen")
        )
    }
}